class Solution {
public:
    TreeNode* trimBST(TreeNode* r, int lo, int hi) {
        if(!r) return nullptr;
        if(r->val<lo) return trimBST(r->right,lo,hi);
        if(r->val>hi) return trimBST(r->left,lo,hi);
        r->left=trimBST(r->left,lo,hi); r->right=trimBST(r->right,lo,hi);
        return r;
    }
};
